
import { defineComponent } from 'vue'

export default defineComponent({
    name: "NavBar",
    data() {
        return {
            hidden: false
        }
    },
    methods: {
        hide() {
            const navBar = document.getElementById('navBar') as HTMLElement
            const hideBtn = document.getElementById('hideBtn') as HTMLElement
            const hideText = document.getElementById('hideText') as HTMLElement

            if(!this.hidden) {
                this.hidden = true
                navBar.style.transform = 'translateX(-5.5rem)'
                hideBtn.style.transform = 'translateX(-5.5rem)'
                hideText.innerText = 'Show'
            } else {
                this.hidden = false
                navBar.style.transform = 'translateX(0)'
                hideBtn.style.transform = 'translateX(0)'
                hideText.innerText = 'Hide'
            }
        }
    }
})
